				const container = buildBody(
					theme, selectedIdx, bake!.stateSnapshot,
					scrollOffset, maxSpec, specW, mode, eventScroll,
				);
				return container.render(specW);
			},
			invalidate: () => {},
		};
		ov.addBody(bodyComponent);

		const modeTag = () =>
			mode === "phases"
				? theme.fg("accent", "PHS")
				: mode === "events"
					? theme.fg("accent", "EVT")
					: mode === "workspace"
						? theme.fg("accent", "WRK")
						: "spc";
		const legend =
			cols >= 48
				? `v:cyc j:dn k:up n/p:ph r:rt s:sk q:q`
				: `v j k n p r s q`;
		ov.addFooter(`${modeTag()} ${legend}`);

		const rebuild = () => {
			tui.requestRender();
		};

